when HTTP_REQUEST {
    switch [HTTP::host] {
        "api.example.com" { pool api_pool }
        "www.example.com" { pool web_pool }
        default { pool default_pool }
    }
}

when HTTP_REQUEST {
    set client [IP::client_addr]
    set count [table incr -subtable ratelimit $client]
    table timeout -subtable ratelimit $client 60
    if { $count > 100 } {
        HTTP::respond 429 content "Rate limit exceeded"
    }
}

when HTTP_REQUEST {
    if { [active_members [LB::server pool]] == 0 } {
        HTTP::respond 503 content {<html><body><h1>Maintenance</h1><p>Service temporarily unavailable.</p></body></html>} "Content-Type" "text/html"
    }
}
